import { Mail, Phone } from 'lucide-react';
import { HoverCard, HoverCardContent, HoverCardTrigger } from '@/shadcn/components/ui/hover-card';
import { Badge } from '@/shadcn/components/ui/badge';
import { UserAvatar } from '@/components/ui/UserAvatar';
import type { User } from '@/types/user';

interface HarmonyUserProfileProps {
  user: Pick<User, 'id' | 'firstName' | 'lastName' | 'fullName' | 'email' | 'phoneNumber' | 'roles' | 'profilePictureUrl'>;
  onNameClick?: () => void;
  cacheKey?: number | null;
}

export function HarmonyUserProfile({ user, onNameClick, cacheKey }: HarmonyUserProfileProps) {
  const displayName = user.fullName
    || `${user.firstName || ''} ${user.lastName || ''}`.trim()
    || 'N/A';

  return (
    <HoverCard openDelay={300} closeDelay={100}>
      <HoverCardTrigger asChild>
        <button
          type="button"
          className="flex items-center gap-2 w-full text-left hover:opacity-75 transition-opacity"
          onClick={(e) => { e.stopPropagation(); onNameClick?.(); }}
        >
          <UserAvatar
            userId={user.id}
            firstName={user.firstName}
            lastName={user.lastName}
            cacheKey={cacheKey}
            className="h-7 w-7 shrink-0"
          />
          <span className="font-semibold text-foreground underline underline-offset-2 decoration-muted-foreground/40">
            {displayName}
          </span>
        </button>
      </HoverCardTrigger>
      <HoverCardContent className="w-72 p-0" align="start" alignOffset={30}>
        <div className="flex items-center gap-3 p-4">
          <UserAvatar
            userId={user.id}
            firstName={user.firstName}
            lastName={user.lastName}
            pictureSize="profile"
            cacheKey={cacheKey}
            className="h-14 w-14 shrink-0"
          />
          <div className="min-w-0">
            <p className="font-semibold text-sm text-foreground truncate">{displayName}</p>
            <div className="flex flex-wrap gap-1 mt-1">
              {user.roles?.length
                ? user.roles.map(role => (
                    <Badge key={role} variant="secondary" className="text-xs px-1.5 py-0">{role}</Badge>
                  ))
                : <span className="text-xs text-muted-foreground">No roles</span>
              }
            </div>
          </div>
        </div>
        <div className="border-t border-border" />
        <div className="flex flex-col gap-2 p-4">
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <Mail className="size-3.5 shrink-0" />
            <span className="truncate">{user.email || '—'}</span>
          </div>
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <Phone className="size-3.5 shrink-0" />
            <span>{user.phoneNumber || '—'}</span>
          </div>
        </div>
      </HoverCardContent>
    </HoverCard>
  );
}
